/**
 * Handler action (what to do with the part).
 */
sealed class HandlerAction {
    
    object Reveal : HandlerAction()
    
    
    data class Hash(
        val `algorithm`: HashAlgorithm) : HandlerAction() {
        companion object
    }
    
    /**
     * Reveal the data (like `Reveal`) and have the verifier evaluate a
     * comparison against it. For `compute_reveal` this behaves as `Reveal`;
     * the assertion spec is carried to the verifier's `reveal_config`.
     */
    data class Assert(
        val `op`: AssertOp, 
        /**
         * How to type the comparison (ordering ops + `between`).
         */
        val `valueType`: AssertValueType?, 
        /**
         * Operands as strings (parsed per `value_type` by the verifier).
         */
        val `value`: kotlin.String?, 
        val `min`: kotlin.String?, 
        val `max`: kotlin.String?, 
        val `inclusive`: kotlin.Boolean?, 
        /**
         * Candidate values for `in`.
         */
        val `values`: List<kotlin.String>?) : HandlerAction() {
        companion object
    }
    

    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeHandlerAction : FfiConverterRustBuffer<HandlerAction>{
    override fun read(buf: ByteBuffer): HandlerAction {
        return when(buf.getInt()) {
            1 -> HandlerAction.Reveal
            2 -> HandlerAction.Hash(
                FfiConverterTypeHashAlgorithm.read(buf),
                )
            3 -> HandlerAction.Assert(
                FfiConverterTypeAssertOp.read(buf),
                FfiConverterOptionalTypeAssertValueType.read(buf),
                FfiConverterOptionalString.read(buf),
                FfiConverterOptionalString.read(buf),
                FfiConverterOptionalString.read(buf),
                FfiConverterOptionalBoolean.read(buf),
                FfiConverterOptionalSequenceString.read(buf),
                )
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: HandlerAction) = when(value) {
        is HandlerAction.Reveal -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is HandlerAction.Hash -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterTypeHashAlgorithm.allocationSize(value.`algorithm`)
            )
        }
        is HandlerAction.Assert -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterTypeAssertOp.allocationSize(value.`op`)
                + FfiConverterOptionalTypeAssertValueType.allocationSize(value.`valueType`)
                + FfiConverterOptionalString.allocationSize(value.`value`)
                + FfiConverterOptionalString.allocationSize(value.`min`)
                + FfiConverterOptionalString.allocationSize(value.`max`)
                + FfiConverterOptionalBoolean.allocationSize(value.`inclusive`)
                + FfiConverterOptionalSequenceString.allocationSize(value.`values`)
            )
        }
    }

    override fun write(value: HandlerAction, buf: ByteBuffer) {
        when(value) {
            is HandlerAction.Reveal -> {
                buf.putInt(1)
                Unit
            }
            is HandlerAction.Hash -> {
                buf.putInt(2)
                FfiConverterTypeHashAlgorithm.write(value.`algorithm`, buf)
                Unit
            }
            is HandlerAction.Assert -> {
                buf.putInt(3)
                FfiConverterTypeAssertOp.write(value.`op`, buf)
                FfiConverterOptionalTypeAssertValueType.write(value.`valueType`, buf)
                FfiConverterOptionalString.write(value.`value`, buf)
                FfiConverterOptionalString.write(value.`min`, buf)
                FfiConverterOptionalString.write(value.`max`, buf)
                FfiConverterOptionalBoolean.write(value.`inclusive`, buf)
                FfiConverterOptionalSequenceString.write(value.`values`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}





