/**
 * Error types for TLSN operations.
 */
sealed class TlsnException: kotlin.Exception() {
    
    class InitializationFailed(
        
        val v1: kotlin.String
        ) : TlsnException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class ConnectionFailed(
        
        val v1: kotlin.String
        ) : TlsnException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class SetupFailed(
        
        val v1: kotlin.String
        ) : TlsnException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class RequestFailed(
        
        val v1: kotlin.String
        ) : TlsnException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class ProofFailed(
        
        val v1: kotlin.String
        ) : TlsnException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class InvalidConfig(
        
        val v1: kotlin.String
        ) : TlsnException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class Timeout(
        ) : TlsnException() {
        override val message
            get() = ""
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<TlsnException> {
        override fun lift(error_buf: RustBuffer.ByValue): TlsnException = FfiConverterTypeTlsnError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeTlsnError : FfiConverterRustBuffer<TlsnException> {
    override fun read(buf: ByteBuffer): TlsnException {
        

        return when(buf.getInt()) {
            1 -> TlsnException.InitializationFailed(
                FfiConverterString.read(buf),
                )
            2 -> TlsnException.ConnectionFailed(
                FfiConverterString.read(buf),
                )
            3 -> TlsnException.SetupFailed(
                FfiConverterString.read(buf),
                )
            4 -> TlsnException.RequestFailed(
                FfiConverterString.read(buf),
                )
            5 -> TlsnException.ProofFailed(
                FfiConverterString.read(buf),
                )
            6 -> TlsnException.InvalidConfig(
                FfiConverterString.read(buf),
                )
            7 -> TlsnException.Timeout()
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: TlsnException): ULong {
        return when(value) {
            is TlsnException.InitializationFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is TlsnException.ConnectionFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is TlsnException.SetupFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is TlsnException.RequestFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is TlsnException.ProofFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is TlsnException.InvalidConfig -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is TlsnException.Timeout -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
        }
    }

    override fun write(value: TlsnException, buf: ByteBuffer) {
        when(value) {
            is TlsnException.InitializationFailed -> {
                buf.putInt(1)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is TlsnException.ConnectionFailed -> {
                buf.putInt(2)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is TlsnException.SetupFailed -> {
                buf.putInt(3)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is TlsnException.RequestFailed -> {
                buf.putInt(4)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is TlsnException.ProofFailed -> {
                buf.putInt(5)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is TlsnException.InvalidConfig -> {
                buf.putInt(6)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is TlsnException.Timeout -> {
                buf.putInt(7)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}





/**
 * Callback interface for receiving proof progress updates.
 *
 * Implement this on the Swift/Kotlin side to receive real-time progress
 * from the Rust prover. Each call includes:
 * - `step`: machine-readable step name (e.g. "MPC_SETUP")
 * - `progress`: 0.0–1.0 fraction
 * - `message`: human-readable description
 */
public interface ProgressCallback {
    
    fun `onProgress`(`step`: kotlin.String, `progress`: kotlin.Double, `message`: kotlin.String)
    
    companion object
}

// Magic number for the Rust proxy to call using the same mechanism as every other method,
// to free the callback once it's dropped by Rust.
internal const val IDX_CALLBACK_FREE = 0
// Callback return codes
internal const val UNIFFI_CALLBACK_SUCCESS = 0
internal const val UNIFFI_CALLBACK_ERROR = 1
internal const val UNIFFI_CALLBACK_UNEXPECTED_ERROR = 2

/**
 * @suppress
 */
public abstract class FfiConverterCallbackInterface<CallbackInterface: Any>: FfiConverter<CallbackInterface, Long> {
    internal val handleMap = UniffiHandleMap<CallbackInterface>()

    internal fun drop(handle: Long) {
        handleMap.remove(handle)
    }

    override fun lift(value: Long): CallbackInterface {
        return handleMap.get(value)
    }

    override fun read(buf: ByteBuffer) = lift(buf.getLong())

    override fun lower(value: CallbackInterface) = handleMap.insert(value)

    override fun allocationSize(value: CallbackInterface) = 8UL

    override fun write(value: CallbackInterface, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}

// Put the implementation in an object so we don't pollute the top-level namespace
internal object uniffiCallbackInterfaceProgressCallback {
    internal object `onProgress`: UniffiCallbackInterfaceProgressCallbackMethod0 {
        override fun callback(`uniffiHandle`: Long,`step`: RustBuffer.ByValue,`progress`: Double,`message`: RustBuffer.ByValue,`uniffiOutReturn`: Pointer,uniffiCallStatus: UniffiRustCallStatus,) {
            val uniffiObj = FfiConverterTypeProgressCallback.handleMap.get(uniffiHandle)
            val makeCall = { ->
                uniffiObj.`onProgress`(
                    FfiConverterString.lift(`step`),
                    FfiConverterDouble.lift(`progress`),
                    FfiConverterString.lift(`message`),
                )
            }
            val writeReturn = { _: Unit -> Unit }
            uniffiTraitInterfaceCall(uniffiCallStatus, makeCall, writeReturn)
        }
    }

    internal object uniffiFree: UniffiCallbackInterfaceFree {
        override fun callback(handle: Long) {
            FfiConverterTypeProgressCallback.handleMap.remove(handle)
        }
    }

    internal var vtable = UniffiVTableCallbackInterfaceProgressCallback.UniffiByValue(
        `onProgress`,
        uniffiFree,
    )

    // Registers the foreign callback with the Rust side.
    // This method is generated for each callback interface.
    internal fun register(lib: UniffiLib) {
        lib.uniffi_tlsn_mobile_fn_init_callback_vtable_progresscallback(vtable)
    }
}

